@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var status = GetStepStatus(stepIndex);
            <li class="step-item flex-fill text-center @status" role="listitem">
                @if (status == "completed")
                {
                    <button class="btn btn-link step-btn p-0 text-decoration-none w-100"
                            @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">&#10003;</span>
                        <span class="step-label text-success fw-semibold d-block mt-1">@StepNames[stepIndex]</span>
                    </button>
                }
                else if (status == "active")
                {
                    <div>
                        <span class="step-circle bg-primary text-white">@(stepIndex + 1)</span>
                        <span class="step-label text-primary fw-bold d-block mt-1">@StepNames[stepIndex]</span>
                    </div>
                }
                else
                {
                    <div>
                        <span class="step-circle bg-secondary text-white opacity-50">@(stepIndex + 1)</span>
                        <span class="step-label text-muted d-block mt-1">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public int CompletedUpTo { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    private string GetStepStatus(int index)
    {
        if (index == CurrentStep) return "active";
        if (index < CompletedUpTo) return "completed";
        return "future";
    }
}

.step-indicator .step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-size: 0.9rem;
    font-weight: 600;
}

.step-indicator .step-btn {
    border: none;
    background: none;
    cursor: pointer;
}

.step-indicator .step-btn:hover .step-label {
    text-decoration: underline;
}

.step-indicator .step-label {
    font-size: 0.85rem;
}

.step-indicator .step-item {
    position: relative;
}

.step-indicator .step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
}

.step-indicator .step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @FieldClass(FullName)" @bind="FullName" @bind:event="oninput" />
    @if (ShowErrors && string.IsNullOrWhiteSpace(FullName))
    {
        <div class="invalid-feedback d-block">Full name is required.</div>
    }
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @FieldClass(Email) @EmailValidationClass()" @bind="Email" @bind:event="oninput" />
    @if (ShowErrors && string.IsNullOrWhiteSpace(Email))
    {
        <div class="invalid-feedback d-block">Email is required.</div>
    }
    else if (_emailError is not null)
    {
        <div class="invalid-feedback d-block">@_emailError</div>
    }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @FieldClass(Phone)" @bind="Phone" @bind:event="oninput" />
    @if (ShowErrors && string.IsNullOrWhiteSpace(Phone))
    {
        <div class="invalid-feedback d-block">Phone is required.</div>
    }
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @FieldClass(Address)" rows="2" @bind="Address" @bind:event="oninput"></textarea>
    @if (ShowErrors && string.IsNullOrWhiteSpace(Address))
    {
        <div class="invalid-feedback d-block">Address is required.</div>
    }
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
        @if (_validating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private bool ShowErrors { get; set; }
    private bool _validating;
    private string? _emailError;

    private string FieldClass(string value) =>
        ShowErrors && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";

    private string EmailValidationClass() =>
        _emailError is not null ? "is-invalid" : "";

    private async Task HandleNext()
    {
        ShowErrors = true;
        _emailError = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email) ||
            string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
            return;

        _validating = true;
        try
        {
            var isValid = await ValidateEmail(Email);
            if (!isValid)
            {
                _emailError = "Please enter a valid email address.";
                return;
            }
        }
        finally
        {
            _validating = false;
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @FieldClass(entry.Company)" value="@entry.Company"
                           @onchange="e => UpdateEntry(index, entry with { Company = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(entry.Company))
                    {
                        <div class="invalid-feedback d-block">Company is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @FieldClass(entry.Title)" value="@entry.Title"
                           @onchange="e => UpdateEntry(index, entry with { Title = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(entry.Title))
                    {
                        <div class="invalid-feedback d-block">Job title is required.</div>
                    }
                </div>
                <div class="col-md-4">
