        finally
        {
            _submitting = false;
        }
    }
}

@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var status = GetStepStatus(stepIndex);
            <li class="step-item flex-fill text-center @status" role="listitem">
                @if (status == "completed")
                {
                    <button class="btn btn-link step-btn p-0 text-decoration-none w-100"
                            @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">&#10003;</span>
                        <span class="step-label text-success fw-semibold d-block mt-1">@StepNames[stepIndex]</span>
                    </button>
                }
                else if (status == "active")
                {
                    <div>
                        <span class="step-circle bg-primary text-white">@(stepIndex + 1)</span>
                        <span class="step-label text-primary fw-bold d-block mt-1">@StepNames[stepIndex]</span>
                    </div>
                }
                else
                {
                    <div>
                        <span class="step-circle bg-secondary text-white opacity-50">@(stepIndex + 1)</span>
                        <span class="step-label text-muted d-block mt-1">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public int CompletedUpTo { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    private string GetStepStatus(int index)
    {
        if (index == CurrentStep) return "active";
        if (index < CompletedUpTo) return "completed";
        return "future";
    }
}

.step-indicator .step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-size: 0.9rem;
    font-weight: 600;
}

.step-indicator .step-btn {
    border: none;
    background: none;
    cursor: pointer;
}

.step-indicator .step-btn:hover .step-label {
    text-decoration: underline;
}

.step-indicator .step-label {
    font-size: 0.85rem;
}

.step-indicator .step-item {
    position: relative;
}

.step-indicator .step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
}

.step-indicator .step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

