.step-indicator .step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-size: 0.9rem;
    font-weight: 600;
}

.step-indicator .step-btn {
    border: none;
    background: none;
    cursor: pointer;
}

.step-indicator .step-btn:hover .step-label {
    text-decoration: underline;
}

.step-indicator .step-label {
    font-size: 0.85rem;
}

.step-indicator .step-item {
    position: relative;
}

.step-indicator .step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    width: calc(100% - 44px);
    height: 2px;
    background-color: #dee2e6;
}

.step-indicator .step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

