@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @FieldClass(FullName)" @bind="FullName" @bind:event="oninput" />
    @if (ShowErrors && string.IsNullOrWhiteSpace(FullName))
    {
        <div class="invalid-feedback d-block">Full name is required.</div>
    }
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @FieldClass(Email) @EmailValidationClass()" @bind="Email" @bind:event="oninput" />
    @if (ShowErrors && string.IsNullOrWhiteSpace(Email))
    {
        <div class="invalid-feedback d-block">Email is required.</div>
    }
    else if (_emailError is not null)
    {
        <div class="invalid-feedback d-block">@_emailError</div>
    }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @FieldClass(Phone)" @bind="Phone" @bind:event="oninput" />
    @if (ShowErrors && string.IsNullOrWhiteSpace(Phone))
    {
        <div class="invalid-feedback d-block">Phone is required.</div>
    }
</div>

