@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @FieldClass(entry.Company)" value="@entry.Company"
                           @onchange="e => UpdateEntry(index, entry with { Company = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(entry.Company))
                    {
                        <div class="invalid-feedback d-block">Company is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @FieldClass(entry.Title)" value="@entry.Title"
                           @onchange="e => UpdateEntry(index, entry with { Title = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(entry.Title))
                    {
                        <div class="invalid-feedback d-block">Job title is required.</div>
                    }
                </div>
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control @(ShowErrors && entry.StartDate == default ? "is-invalid" : "")"
                           value="@(entry.StartDate == default ? "" : entry.StartDate.ToString("yyyy-MM-dd"))"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : default })" />
                    @if (ShowErrors && entry.StartDate == default)
                    {
                        <div class="invalid-feedback d-block">Start date is required.</div>
                    }
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" disabled="@entry.IsCurrent"
                           value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null })" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="current-@index" checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
                <div class="col-12">
                    <label class="form-label">Description <span class="text-danger">*</span></label>
                    <textarea class="form-control @FieldClass(entry.Description)" rows="3" value="@entry.Description"
                              @onchange="e => UpdateEntry(index, entry with { Description = e.Value?.ToString() ?? string.Empty })"></textarea>
                    @if (ShowErrors && string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="invalid-feedback d-block">Description is required.</div>
                    }
                </div>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    <span class="me-1">+</span> Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private bool ShowErrors { get; set; }

    private string FieldClass(string value) =>
        ShowErrors && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ShowErrors = true;
        var allValid = Entries.All(e =>
            !string.IsNullOrWhiteSpace(e.Company) &&
            !string.IsNullOrWhiteSpace(e.Title) &&
            e.StartDate != default &&
            !string.IsNullOrWhiteSpace(e.Description));

        if (!allValid) return;

        await OnNext.InvokeAsync();
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

