@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row g-3">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @FieldClass(reference.Name)" value="@reference.Name"
                           @onchange="e => UpdateReference(index, reference with { Name = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(reference.Name))
                    {
                        <div class="invalid-feedback d-block">Name is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @FieldClass(reference.Relationship)" value="@reference.Relationship"
                           @onchange="e => UpdateReference(index, reference with { Relationship = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(reference.Relationship))
                    {
                        <div class="invalid-feedback d-block">Relationship is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control @FieldClass(reference.Email)" value="@reference.Email"
                           @onchange="e => UpdateReference(index, reference with { Email = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(reference.Email))
                    {
                        <div class="invalid-feedback d-block">Email is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control @FieldClass(reference.Phone)" value="@reference.Phone"
                           @onchange="e => UpdateReference(index, reference with { Phone = e.Value?.ToString() ?? string.Empty })" />
                    @if (ShowErrors && string.IsNullOrWhiteSpace(reference.Phone))
                    {
                        <div class="invalid-feedback d-block">Phone is required.</div>
                    }
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-primary mb-3" @onclick="AddReference">
        <span class="me-1">+</span> Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = [];
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private bool ShowErrors { get; set; }

    private string FieldClass(string value) =>
        ShowErrors && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";

    private void UpdateReference(int index, ReferenceModel updated)
    {
        References[index] = updated;
    }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ShowErrors = true;
        var allValid = References.All(r =>
            !string.IsNullOrWhiteSpace(r.Name) &&
            !string.IsNullOrWhiteSpace(r.Relationship) &&
            !string.IsNullOrWhiteSpace(r.Email) &&
            !string.IsNullOrWhiteSpace(r.Phone));

        if (!allValid) return;

        await OnNext.InvokeAsync();
    }

    public record ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

