@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label for="coverLetter" class="form-label">Write your cover letter</label>
    <textarea id="coverLetter" class="form-control @(ShowErrors && string.IsNullOrWhiteSpace(CoverLetter) ? "is-invalid" : "")"
              rows="12" maxlength="@MaxLength" value="@CoverLetter"
              @oninput="HandleInput"></textarea>
    @if (ShowErrors && string.IsNullOrWhiteSpace(CoverLetter))
    {
        <div class="invalid-feedback">A cover letter is required.</div>
    }
    <div class="form-text text-end">@(CoverLetter?.Length ?? 0) / @MaxLength characters</div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private bool ShowErrors { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        if (value.Length > MaxLength)
            value = value[..MaxLength];
        CoverLetter = value;
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        ShowErrors = true;
        if (string.IsNullOrWhiteSpace(CoverLetter)) return;
        await OnNext.InvokeAsync();
    }
}

