@namespace sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication

<h4 class="mb-4">Review Your Application</h4>

@if (Submitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt>
                <dd class="col-sm-9">@FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Address</dd>
            </dl>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <h6>@entry.Title at @entry.Company</h6>
                    <p class="text-muted mb-1">
                        @entry.StartDate.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </p>
                    <p class="mb-0">@entry.Description</p>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <span class="text-muted">@r.Email &bull; @r.Phone</span>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (_errorMessage is not null)
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
            @if (_submitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkHistoryStep.WorkEntryModel> WorkEntries { get; set; } = [];
    [Parameter] public List<ReferencesStep.ReferenceModel> References { get; set; } = [];
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool _submitting;
    private bool Submitted;
    private int ApplicationId;
    private string? _errorMessage;

    private async Task HandleSubmit()
    {
        _submitting = true;
        _errorMessage = null;
        try
        {
            ApplicationId = await OnSubmit();
            Submitted = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            _submitting = false;
        }
    }
}

