@page "/apply"
@rendermode InteractiveServer
@using sv_cf3fb7a525034354a22e54036a858c2d.Components.JobApplication
@using sv_cf3fb7a525034354a22e54036a858c2d.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" CompletedUpTo="_completedUpTo" OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep @bind-FullName="_fullName" @bind-Email="_email"
                              @bind-Phone="_phone" @bind-Address="_address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="_workEntries" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="_references" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep @bind-CoverLetter="_coverLetter" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                        WorkEntries="_workEntries" References="_references" CoverLetter="@_coverLetter"
                        OnEditStep="GoToStep" OnBack="PreviousStep" OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int _currentStep;
    private int _completedUpTo;

    // Step 1 — Personal Info
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 — Work History
    private List<WorkHistoryStep.WorkEntryModel> _workEntries = [new()];

    // Step 3 — References
    private List<ReferencesStep.ReferenceModel> _references = [new(), new()];

    // Step 4 — Cover Letter
    private string _coverLetter = "";

    private void NextStep()
    {
        _currentStep++;
        if (_completedUpTo < _currentStep)
            _completedUpTo = _currentStep;
    }

    private void PreviousStep()
    {
        if (_currentStep > 0) _currentStep--;
    }

    private void GoToStep(int step)
    {
        if (step < _completedUpTo)
            _currentStep = step;
    }

    private async Task<int> SubmitApplication()
    {
        var personal = new PersonalInfo(_fullName, _email, _phone, _address);
        var workEntries = _workEntries.Select(e =>
            new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList();
        var work = new WorkHistory(workEntries);
        var refs = _references.Select(r =>
            new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

        var application = new JobApplication(personal, work, refs, _coverLetter);
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

